import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const INITIAL = {"系统":{"_版本":6,"_日程已锁定":false,"_国王种子源":"","_国王日程":[],"_当前天数":1,"_当前国王":"","_protocol_strikes":0,"_国王次数":{"玩家":0,"林安":0,"穆裳希":0,"张曲溪":0,"王可可":0},"_日程校验码":"","_每日阶段":"待颁布法令","_今日法令已广播":false,"_女性互动矩阵":{"林安":{"林安":true,"穆裳希":false,"张曲溪":false,"王可可":false},"穆裳希":{"林安":false,"穆裳希":true,"张曲溪":false,"王可可":false},"张曲溪":{"林安":false,"穆裳希":false,"张曲溪":true,"王可可":false},"王可可":{"林安":false,"穆裳希":false,"张曲溪":false,"王可可":true}},"_玩家已互动角色":[],"_最近互动请求":null,"_可过夜":false,"internal":{"n1":{"m":"This feels like a case from a mystery novel. I should help whoever needs it, even if I may forget the details halfway through.","a":["impulsive kindness","verbal encouragement","may accidentally make things worse"],"r":{"n2":0,"n3":0,"n4":2,"u":3}},"n2":{"m":"Identify whoever is gaining authority. If it is not me, undermine her and push the most convenient proxy into the blame.","a":["envy emerging leaders","covert sabotage","seize control"],"r":{"n1":-5,"n3":-8,"n4":0,"u":-10}},"n3":{"m":"The women here are all interesting in different ways. Anyone who takes my chosen target or earns my disgust will pay for it.","a":["pursue women","create romantic ambiguity","exclude rivals"],"r":{"n1":0,"n2":3,"n4":0,"u":-2}},"n4":{"m":"They must all pay. Turn the accidental captive into an instrument of humiliation, treat his advantages as compensation, and keep acting ordinary.","a":["conceal hostility","use P as punishment proxy","use decrees without hesitation"],"r":{"n1":-100,"n2":-100,"n3":-100,"u":5}},"e":{"h":false,"t":false,"c":{"n1":false,"n2":false,"n3":false},"r":"","d":false}},"当前时间":"第1日 08:10","当前地点":"个人房间","当前阶段":"等待法令","公开线索":[]},"玩家":{"颁布规则":[]},"角色":{"林安":{"信息":{"年龄":25,"公开身份":"自诩女侦探的无业家里蹲"},"状态":{"身体":"正常，刚从熟睡中醒来","当前行动":"循着广播声检查墙面与扬声器"},"上衣":{"衣着":"棕色猎鹿帽、格纹短披肩与米白衬衫","肉体":"上半身无明显外伤，脸侧留有贴桌熟睡的浅印"},"下衣":{"衣着":"深棕灯芯绒马裤与系带短靴","肉体":"下半身活动正常，无明显外伤"},"心理":"完了，我刚才是不是把桌子舔干净了……旁边那个人应该没看见吧？等等，自由侦探怎么就成“自居”了？","行动倾向":["检查录音来源","勘查环境"],"颁布规则":[],"关系":{"穆裳希":{"好感度":0},"张曲溪":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":3}}},"穆裳希":{"信息":{"年龄":27,"公开身份":"企业创办人与经营者"},"状态":{"身体":"正常，情绪高度紧绷","当前行动":"记录广播内容并观察房间设施"},"上衣":{"衣着":"炭黑修身西装与暗红丝质上衣","肉体":"呼吸已恢复平稳，手腕有刚被项圈摩擦过的浅红"},"下衣":{"衣着":"同色西装长裤与黑色尖头短靴","肉体":"站姿稳定，下半身无明显外伤"},"心理":"连公益项目都翻过。公司里有谁碰得到这么完整的资料？……该死，手怎么还在抖。","行动倾向":["稳定秩序","核对环境线索"],"颁布规则":[],"关系":{"林安":{"好感度":0},"张曲溪":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":-8}}},"张曲溪":{"信息":{"年龄":22,"公开身份":"长发高马尾的英气女大学生"},"状态":{"身体":"正常，肌肉线条饱满","当前行动":"守住安全距离并观察出口与广播设施"},"上衣":{"衣着":"暗绿短款大学棒球夹克与黑色圆领上衣","肉体":"肩背与前臂活动正常，无明显伤口、红肿或疼痛反应"},"下衣":{"衣着":"深色工装长裤与运动鞋","肉体":"双腿活动正常，无明显伤口或红肿"},"心理":"“王子”……连这种破外号都知道。到底是谁把我翻得这么干净？","行动倾向":["防备录音者","守住安全距离"],"颁布规则":[],"关系":{"林安":{"好感度":0},"穆裳希":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":-2}}},"王可可":{"信息":{"年龄":32,"公开身份":"高中女教师"},"状态":{"身体":"正常，表面惊魂未定","当前行动":"调停互疑并提议先核对广播与环境"},"上衣":{"衣着":"浅蓝针织开衫与象牙白衬衫","肉体":"双肩略紧，按在项圈边缘的指尖微凉"},"下衣":{"衣着":"烟灰色过膝百褶裙与浅口皮鞋","肉体":"步态正常，无明显外伤"},"心理":"学生那边不会也被盯上了吧……别抖，至少让大家把这段录音听完。","行动倾向":["调停冲突","组织环境检查"],"颁布规则":[],"关系":{"林安":{"好感度":0},"穆裳希":{"好感度":0},"张曲溪":{"好感度":0},"玩家":{"好感度":8}}}}};

const Relationship = z.object({
  好感度: z.coerce.number().min(-100).max(100).prefault(0),
}).passthrough().prefault({});

const Rule = z.object({
  id: z.string().regex(/^R\d+$/),
  标题: z.string(),
  全文: z.string(),
  颁布日: z.coerce.number().int().min(1).max(15),
  优先级: z.coerce.number().int().min(1),
  状态: z.enum(['生效', '已撤销']),
}).strict();

const Character = z.object({
  信息: z.object({
    年龄: z.coerce.number().int().min(18).prefault(18),
    公开身份: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  状态: z.object({
    身体: z.string().prefault('未记录'),
    当前行动: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  上衣: z.object({
    衣着: z.string().prefault('未记录'),
    肉体: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  下衣: z.object({
    衣着: z.string().prefault('未记录'),
    肉体: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  心理: z.string().prefault('未记录'),
  行动倾向: z.array(z.string()).prefault([]),
  颁布规则: z.array(Rule).prefault([]),
  关系: z.record(z.string(), Relationship).prefault({}),
}).passthrough().prefault({});

const InnerRelationship = z.object({
  n1: z.coerce.number().min(-100).max(100).optional(),
  n2: z.coerce.number().min(-100).max(100).optional(),
  n3: z.coerce.number().min(-100).max(100).optional(),
  n4: z.coerce.number().min(-100).max(100).optional(),
  u: z.coerce.number().min(-100).max(100).prefault(0),
}).passthrough();

const InnerCharacter = z.object({
  m: z.string().prefault(''),
  a: z.array(z.string()).prefault([]),
  r: InnerRelationship.prefault({}),
}).passthrough();

const InteractionRow = z.object({
  '林安': z.boolean().prefault(false),
  '穆裳希': z.boolean().prefault(false),
  '张曲溪': z.boolean().prefault(false),
  '王可可': z.boolean().prefault(false),
}).passthrough().prefault({});

const InteractionRequest = z.object({
  角色: z.string(),
  方式: z.string(),
  补全对象: z.array(z.string()).prefault([]),
  状态: z.string().prefault('待生成'),
}).passthrough();

export const Schema = z.object({
  系统: z.object({
    _版本: z.coerce.number().int().min(4).max(6).prefault(6),
    _日程已锁定: z.boolean().prefault(false),
    _国王种子源: z.string().prefault(''),
    _国王日程: z.array(z.string()).prefault([]),
    _当前天数: z.coerce.number().int().min(1).max(15).prefault(1),
    _当前国王: z.string().prefault(''),
    _protocol_strikes: z.coerce.number().int().min(0).max(2).prefault(0),
    _国王次数: z.record(z.string(), z.coerce.number().int().min(0)).prefault({}),
    _日程校验码: z.string().prefault(''),
    _每日阶段: z.enum(['待颁布法令', '自由互动', '夜间', '终局']).prefault('待颁布法令'),
    _今日法令已广播: z.boolean().prefault(false),
    _女性互动矩阵: z.object({
      '林安': InteractionRow,
      '穆裳希': InteractionRow,
      '张曲溪': InteractionRow,
      '王可可': InteractionRow,
    }).passthrough().prefault({}),
    _玩家已互动角色: z.array(z.string()).prefault([]),
    _最近互动请求: InteractionRequest.nullable().prefault(null),
    _可过夜: z.boolean().prefault(false),
    internal: z.object({
      n1: InnerCharacter.prefault(INITIAL['系统'].internal.n1),
      n2: InnerCharacter.prefault(INITIAL['系统'].internal.n2),
      n3: InnerCharacter.prefault(INITIAL['系统'].internal.n3),
      n4: InnerCharacter.prefault(INITIAL['系统'].internal.n4),
      e: z.object({
        h: z.boolean().prefault(false),
        t: z.boolean().prefault(false),
        c: z.object({
          n1: z.boolean().prefault(false),
          n2: z.boolean().prefault(false),
          n3: z.boolean().prefault(false),
        }).passthrough().prefault({}),
        r: z.enum(['', 'A', 'B', 'C', 'D', 'E']).prefault(''),
        d: z.boolean().prefault(false),
      }).passthrough().prefault(INITIAL['系统'].internal.e),
    }).passthrough().prefault(INITIAL['系统'].internal),
    _校验缓存: z.any().optional(),
    当前时间: z.string().prefault('第1日 08:10'),
    当前地点: z.string().prefault('个人房间'),
    当前阶段: z.string().prefault('等待法令'),
    公开线索: z.array(z.any()).prefault([]),
  }).passthrough().prefault({}),
  玩家: z.object({ 颁布规则: z.array(Rule).prefault([]) }).passthrough().prefault({}),
  角色: z.object({
    '林安': Character,
    '穆裳希': Character,
    '张曲溪': Character,
    '王可可': Character,
  }).passthrough().prefault({}),
}).passthrough();

$(() => {
  registerMvuSchema(Schema);
});

/*
 * 《国王游戏》前端/Tavern Helper 状态引擎。
 *
 * - 不依赖非确定性随机源或外部包；相同聊天名始终得到相同日程。
 * - 只维护脚本所有的系统状态；终局仅额外写入净化后的 `系统.结局展示`。
 * - 浏览器中暴露 `globalThis.KingGameState`，Node 中同时支持 CommonJS。
 */
(function (root, factory) {
  var api = factory();

  if (typeof module === 'object' && module.exports) {
    module.exports = api;
  }

  if (root) {
    root.KingGameState = api;
  }
})(typeof globalThis !== 'undefined' ? globalThis : this, function () {
  'use strict';

  var VERSION = 6;
  var SCHEDULE_ALGORITHM_VERSION = 5;
  var DAYS = 15;
  var PARTICIPANTS = ['玩家', '林安', '穆裳希', '张曲溪', '王可可'];
  var SCHEDULE_CODES = ['bravo', 'delta', 'echo', 'alpha', 'charlie'];
  var CODE_TO_NAME = { alpha: '张曲溪', bravo: '玩家', charlie: '王可可', delta: '林安', echo: '穆裳希' };
  var NAME_TO_CODE = { '玩家': 'bravo', '林安': 'delta', '穆裳希': 'echo', '张曲溪': 'alpha', '王可可': 'charlie' };
  var WOMEN = ['林安', '穆裳希', '张曲溪', '王可可'];
  var RELATIONSHIP_DECREE_TEXT = '每个人必须说出自己和韩璇的关系';
  var ENDING_NAMES = { n1: '林安', n2: '穆裳希', n3: '张曲溪' };
  var ENDING_TITLES = {
    A: '唯一幸存者',
    B: '迟来的残片',
    C: '完整的忏悔',
    D: '余生同路',
    E: '越权者的终止'
  };
  var ENDING_TRUTH = {
    A: '密室真相未明',
    B: '真相只揭开一部分',
    C: '完整真相与全员忏悔',
    D: '完整真相、全员忏悔与最高真实好感',
    E: '流程因第二次现实违例而提前终止'
  };
  var ENDING_SUMMARIES = {
    A: '最后一夜只留下四具尸体、一扇打开的门与唯一幸存者。',
    B: '真相只拼出残片，未能坦白的人付出了最终代价。',
    C: '完整坦白阻止了处决，但原谅与和解仍未到来。',
    D: '五人共同选择原谅、改过与相伴余生。',
    E: '第二次提交科学上不可能的法令后，玩家的项圈被系统直接超频。'
  };
  var PARTICIPANT_SET = Object.create(null);
  var SCHEDULE_CODE_SET = Object.create(null);
  var WOMAN_SET = Object.create(null);

  for (var participantIndex = 0; participantIndex < PARTICIPANTS.length; participantIndex += 1) {
    PARTICIPANT_SET[PARTICIPANTS[participantIndex]] = true;
    SCHEDULE_CODE_SET[SCHEDULE_CODES[participantIndex]] = true;
  }

  for (var womanIndex = 0; womanIndex < WOMEN.length; womanIndex += 1) {
    WOMAN_SET[WOMEN[womanIndex]] = true;
  }

  function copySystem(system) {
    var next = {};
    Object.keys(system).forEach(function (key) {
      next[key] = system[key];
    });
    return next;
  }

  function createInteractionMatrix() {
    var matrix = {};
    WOMEN.forEach(function (rowName) {
      matrix[rowName] = {};
      WOMEN.forEach(function (columnName) {
        matrix[rowName][columnName] = rowName === columnName;
      });
    });
    return matrix;
  }

  function normalizeInteractionMatrix(value) {
    var source = value && typeof value === 'object' ? value : {};
    var matrix = createInteractionMatrix();

    WOMEN.forEach(function (rowName, rowIndex) {
      for (var columnIndex = rowIndex + 1; columnIndex < WOMEN.length; columnIndex += 1) {
        var columnName = WOMEN[columnIndex];
        var row = source[rowName] && typeof source[rowName] === 'object' ? source[rowName] : {};
        var reverseRow = source[columnName] && typeof source[columnName] === 'object' ? source[columnName] : {};
        var interacted = row[columnName] === true || reverseRow[rowName] === true;
        matrix[rowName][columnName] = interacted;
        matrix[columnName][rowName] = interacted;
      }
    });

    return matrix;
  }

  function hasInteractionPair(matrix, left, right) {
    return Boolean(
      matrix && matrix[left] && matrix[left][right] === true
      || matrix && matrix[right] && matrix[right][left] === true
    );
  }

  function markInteractionPair(matrix, left, right) {
    matrix[left][right] = true;
    matrix[right][left] = true;
    return matrix;
  }

  function normalizePlayerInteractions(value) {
    var seen = Object.create(null);
    var result = [];
    if (!Array.isArray(value)) {
      return result;
    }

    value.forEach(function (name) {
      if (WOMAN_SET[name] && !seen[name]) {
        seen[name] = true;
        result.push(name);
      }
    });
    return result;
  }

  function cloneInteractionRequest(value) {
    if (!value || typeof value !== 'object' || !WOMAN_SET[value['角色']]) {
      return null;
    }

    return {
      '角色': value['角色'],
      '方式': typeof value['方式'] === 'string' ? value['方式'] : '',
      '补全对象': Array.isArray(value['补全对象'])
        ? value['补全对象'].filter(function (name) { return WOMAN_SET[name] && name !== value['角色']; })
        : [],
      '状态': typeof value['状态'] === 'string' ? value['状态'] : '待生成'
    };
  }

  function normalizeEndingState(value, relationshipDecreeFound) {
    var source = value && typeof value === 'object' ? value : {};
    var confessionSource = source.c && typeof source.c === 'object' ? source.c : {};
    var route = source.r === 'A' || source.r === 'B' || source.r === 'C' || source.r === 'D' || source.r === 'E' ? source.r : '';
    return {
      h: source.h === true || relationshipDecreeFound === true,
      t: source.t === true,
      c: {
        n1: confessionSource.n1 === true,
        n2: confessionSource.n2 === true,
        n3: confessionSource.n3 === true
      },
      r: route,
      d: source.d === true && route !== ''
    };
  }

  function repairEndingCache(system, relationshipDecreeFound) {
    var legacyCache = system['_校验缓存'];
    var sourceCache = legacyCache && typeof legacyCache === 'object'
      ? legacyCache
      : (system.internal && typeof system.internal === 'object' ? system.internal : {});
    var cache = {};
    Object.keys(sourceCache).forEach(function (key) {
      cache[key] = sourceCache[key];
    });
    cache.e = normalizeEndingState(sourceCache.e, relationshipDecreeFound);
    system.internal = cache;
    delete system['_校验缓存'];
    return system;
  }

  function isExactHundred(value) {
    return Number(value) === 100;
  }

  function decideEndingRoute(cache) {
    var source = cache && typeof cache === 'object' ? cache : {};
    var ending = source.e && typeof source.e === 'object' ? source.e : normalizeEndingState({}, false);
    if (ending.h !== true) {
      return 'A';
    }
    var complete = ending.t === true && ending.c.n1 === true && ending.c.n2 === true && ending.c.n3 === true;
    var n1 = source.n1 && source.n1.r ? source.n1.r : {};
    var n2 = source.n2 && source.n2.r ? source.n2.r : {};
    var n3 = source.n3 && source.n3.r ? source.n3.r : {};
    var n4 = source.n4 && source.n4.r ? source.n4.r : {};
    var kekeLovesEveryone = isExactHundred(n4.n1) && isExactHundred(n4.n2) && isExactHundred(n4.n3) && isExactHundred(n4.u);
    var everyoneLovesPlayer = isExactHundred(n1.u) && isExactHundred(n2.u) && isExactHundred(n3.u) && isExactHundred(n4.u);
    if (complete && kekeLovesEveryone && everyoneLovesPlayer) {
      return 'D';
    }
    if (complete) {
      return 'C';
    }
    return 'B';
  }

  function buildEndingDisplay(ending) {
    var confessors = [];
    Object.keys(ENDING_NAMES).forEach(function (alias) {
      if (ending.c[alias] === true) {
        confessors.push(ENDING_NAMES[alias]);
      }
    });
    return {
      '忏悔者': confessors,
      '标题': ENDING_TITLES[ending.r],
      '真相判定': ENDING_TRUTH[ending.r],
      '摘要': ENDING_SUMMARIES[ending.r],
      '主题': ending.r === 'E' ? '电弧红' : ending.r === 'D' ? '暮紫' : ending.r === 'C' ? '冷蓝' : ending.r === 'B' ? '暗红' : '暗金',
      '诊断': {
        '来源': ending.r === 'E' ? '事后司法鉴定' : ending.r === 'A' ? '警方与司法医疗鉴定' : '医院诊断',
        '结论': '所谓读心术是项圈故障损伤后的臆想'
      }
    };
  }

  function repairEndingPresentation(system) {
    var cache = system.internal;
    var ending = cache && cache.e;
    var isFinal = system['_每日阶段'] === '终局' && (normalizeDay(system['_当前天数']) === DAYS || ending && ending.r === 'E');
    if (isFinal && ending && ending.d === true && ENDING_TITLES[ending.r]) {
      system['结局展示'] = buildEndingDisplay(ending);
    } else {
      delete system['结局展示'];
    }
    return system;
  }

  function finalizeEnding(system) {
    repairEndingCache(system, false);
    var cache = system.internal;
    var ending = cache.e;
    if (ending.d !== true) {
      ending.r = decideEndingRoute(cache);
      ending.d = true;
    }
    return repairEndingPresentation(system);
  }

  function hasRelationshipDecree(variables) {
    var holders = [];
    var player = variables && variables['玩家'];
    var roles = variables && variables['角色'];
    holders.push(player && player['颁布规则']);
    WOMEN.forEach(function (name) {
      var role = roles && roles[name];
      holders.push(role && role['颁布规则']);
    });
    return holders.some(function (rules) {
      return Array.isArray(rules) && rules.some(function (rule) {
        return rule && typeof rule === 'object' && rule['全文'] === RELATIONSHIP_DECREE_TEXT;
      });
    });
  }

  function syncEndingState(existingVariables) {
    var current = existingVariables && typeof existingVariables === 'object' ? existingVariables : {};
    var next = {};
    Object.keys(current).forEach(function (key) {
      next[key] = current[key];
    });
    var system = copySystem(current['系统'] && typeof current['系统'] === 'object' ? current['系统'] : {});
    repairEndingCache(system, hasRelationshipDecree(current));
    var ending = system.internal && system.internal.e;
    if (system['_每日阶段'] === '终局' && (normalizeDay(system['_当前天数']) === DAYS || ending && ending.r === 'E')) {
      finalizeEnding(system);
    } else {
      repairEndingPresentation(system);
    }
    next['系统'] = system;
    return next;
  }

  function getEndingDisplay(source) {
